        html: `<section class="section about-features-premium" style="padding:100px 20px;background:#f8fafc;"><div style="max-width:1200px;margin:0 auto;"><div style="text-align:center;margin-bottom:64px;"><h2 style="font-size:42px;color:#1a202c;margin-bottom:16px;font-weight:700;">Почему выбирают нас</h2><p style="font-size:18px;color:#64748b;">Преимущества работы с нашей командой</p></div><div style="display:grid;grid-template-columns:repeat(2,1fr);gap:32px;"><div style="display:flex;gap:24px;padding:32px;background:white;border-radius:20px;box-shadow:0 4px 20px rgba(0,0,0,0.05);"><div style="width:64px;height:64px;background:linear-gradient(135deg,#6366f1,#8b5cf6);border-radius:18px;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><i class="fas fa-rocket" style="font-size:26px;color:white;"></i></div><div><h3 style="font-size:22px;color:#1a202c;margin-bottom:12px;font-weight:700;">Быстро</h3><p style="color:#64748b;line-height:1.6;">Соблюдаем сроки и всегда доставляем результат вовремя</p></div></div><div style="display:flex;gap:24px;padding:32px;background:white;border-radius:20px;box-shadow:0 4px 20px rgba(0,0,0,0.05);"><div style="width:64px;height:64px;background:linearGradient(135deg,#10b981,#059669);border-radius:18px;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><i class="fas fa-shield-alt" style="font-size:26px;color:white;"></i></div><div><h3 style="font-size:22px;color:#1a202c;margin-bottom:12px;font-weight:700;">Надёжно</h3><p style="color:#64748b;line-height:1.6;">Гарантия качества и защита ваших данных</p></div></div><div style="display:flex;gap:24px;padding:32px;background:white;border-radius:20px;box-shadow:0 4px 20px rgba(0,0,0,0.05);"><div style="width:64px;height:64px;background:linear-gradient(135deg,#f59e0b,#d97706);border-radius:18px;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><i class="fas fa-gem" style="font-size:26px;color:white;"></i></div><div><h3 style="font-size:22px;color:#1a202c;margin-bottom:12px;font-weight:700;">Качественно</h3><p style="color:#64748b;line-height:1.6;">Премиальное качество всех наших услуг</p></div></div><div style="display:flex;gap:24px;padding:32px;background:white;border-radius:20px;box-shadow:0 4px 20px rgba(0,0,0,0.05);"><div style="width:64px;height:64px;background:linear-gradient(135deg,#ec4899,#8b5cf6);border-radius:18px;display:flex;align-items:center;justify-content:center;flex-shrink:0;"><i class="fas fa-headset" style="font-size:26px;color:white;"></i></div><div><h3 style="font-size:22px;color:#1a202c;margin-bottom:12px;font-weight:700;">Поддержка 24/7</h3><p style="color:#64748b;line-height:1.6;">Всегда на связи и готовы помочь в любое время</p></div></div></div></div></section>`,
