        preview: `<svg viewBox="0 0 200 80" xmlns="http://www.w3.org/2000/svg"><rect width="200" height="80" fill="#ffffff"/><text x="100" y="14" text-anchor="middle" fill="#1a202c" font-size="8" font-weight="700">Наши эксперты</text><circle cx="36" cy="36" r="14" fill="#6366f1" opacity="0.2"/><circle cx="36" cy="34" r="8" fill="#6366f1" opacity="0.5"/><text x="36" y="56" text-anchor="middle" fill="#1a202c" font-size="4" font-weight="600">CEO</text><circle cx="82" cy="36" r="14" fill="#10b981" opacity="0.2"/><circle cx="82" cy="34" r="8" fill="#10b981" opacity="0.5"/><text x="82" y="56" text-anchor="middle" fill="#1a202c" font-size="4" font-weight="600">Арт</text><circle cx="128" cy="36" r="14" fill="#f59e0b" opacity="0.2"/><circle cx="128" cy="34" r="8" fill="#f59e0b" opacity="0.5"/><text x="128" y="56" text-anchor="middle" fill="#1a202c" font-size="4" font-weight="600">Tech</text><circle cx="174" cy="36" r="14" fill="#ec4899" opacity="0.2"/><circle cx="174" cy="34" r="8" fill="#ec4899" opacity="0.5"/><text x="174" y="56" text-anchor="middle" fill="#1a202c" font-size="4" font-weight="600">Marketing</text></svg>`,
        html: `<section class="section about-team-grid" style="padding:100px 20px;background:#ffffff;"><div style="max-width:1200px;margin:0 auto;"><div style="text-align:center;margin-bottom:64px;"><h2 style="font-size:42px;color:#1a202c;margin-bottom:16px;font-weight:700;">Наши эксперты</h2><p style="font-size:18px;color:#64748b;">Профессионалы, которые работают над вашим проектом</p></div><div style="display:grid;grid-template-columns:repeat(4,1fr);gap:24px;"><div style="text-align:center;"><img src="https://images.unsplash.com/photo-1560250097-0b93528c311a?w=300" style="width:180px;height:180px;border-radius:50%;object-fit:cover;margin:0 auto 20px;box-shadow:0 10px 30px rgba(0,0,0,0.1);"><h4 style="font-size:18px;color:#1a202c;margin-bottom:4px;font-weight:600;">Александр Петров</h4><p style="color:#6366f1;font-size:14px;">CEO & Founder</p></div><div style="text-align:center;"><img src="https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=300" style="width:180px;height:180px;border-radius:50%;object-fit:cover;margin:0 auto 20px;box-shadow:0 10px 30px rgba(0,0,0,0.1);"><h4 style="font-size:18px;color:#1a202c;margin-bottom:4px;font-weight:600;">Анна Сидорова</h4><p style="color:#6366f1;font-size:14px;">Арт-директор</p></div><div style="text-align:center;"><img src="https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=300" style="width:180px;height:180px;border-radius:50%;object-fit:cover;margin:0 auto 20px;box-shadow:0 10px 30px rgba(0,0,0,0.1);"><h4 style="font-size:18px;color:#1a202c;margin-bottom:4px;font-weight:600;">Максим Козлов</h4><p style="color:#6366f1;font-size:14px;">Технический директор</p></div><div style="text-align:center;"><img src="https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=300" style="width:180px;height:180px;border-radius:50%;object-fit:cover;margin:0 auto 20px;box-shadow:0 10px 30px rgba(0,0,0,0.1);"><h4 style="font-size:18px;color:#1a202c;margin-bottom:4px;font-weight:600;">Елена Морозова</h4><p style="color:#6366f1;font-size:14px;">Маркетолог</p></div></div></div></section>`,
