        preview: `<svg viewBox="0 0 200 80" xmlns="http://www.w3.org/2000/svg"><rect width="200" height="80" fill="#ffffff"/><rect x="14" y="14" width="40" height="3" rx="1.5" fill="url(#tx1line)"/><rect x="14" y="26" width="172" height="2" rx="1" fill="#e2e8f0"/><rect x="14" y="32" width="160" height="2" rx="1" fill="#e2e8f0"/><rect x="14" y="38" width="170" height="2" rx="1" fill="#e2e8f0"/><rect x="14" y="50" width="172" height="2" rx="1" fill="#e2e8f0"/><rect x="14" y="56" width="155" height="2" rx="1" fill="#e2e8f0"/><rect x="14" y="62" width="165" height="2" rx="1" fill="#e2e8f0"/><defs><linearGradient id="tx1line" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" style="stop-color:#6366f1"/><stop offset="100%" style="stop-color:#8b5cf6"/></linearGradient></defs></svg>`,
        html: `<section class="section text-classic-premium" style="padding:80px 20px;background:#ffffff;"><div style="max-width:800px;margin:0 auto;"><div style="width:60px;height:4px;background:linear-gradient(135deg,#6366f1,#8b5cf6);margin-bottom:32px;"></div><p style="font-size:18px;color:#4a5568;line-height:1.8;margin-bottom:24px;">Это пример текстового блока. Здесь вы можете разместить описание вашего продукта или услуги.</p><p style="font-size:18px;color:#4a5568;line-height:1.8;">Добавляйте несколько абзацев для подробного описания.</p></div></section>`,
